begin;create table if not exists public.commercial_ai_playbooks(id uuid primary key default gen_random_uuid(),organization_id uuid not null references public.organizations(id)on delete cascade,scope_type text not null check(scope_type in('organization','developer')),developer_name text,stage_key text not null check(stage_key in('abordagem','qualificacao','apresentacao','simulacao','visita','proposta','fechamento','reativacao')),version integer not null,status text not null check(status in('draft','active','retired'))default'draft',objective text not null,questions text[]not null,actions text[]not null,exit_criteria text[]not null,prohibited_actions text[]not null,created_by uuid not null references public.profiles(id),approved_by uuid references public.profiles(id),approved_at timestamptz,created_at timestamptz not null default now(),unique(organization_id,scope_type,developer_name,stage_key,version),check((scope_type='developer'and developer_name is not null)or(scope_type='organization'and developer_name is null)),check(cardinality(questions)between 1 and 8 and cardinality(actions)between 1 and 8 and cardinality(exit_criteria)between 1 and 8 and cardinality(prohibited_actions)between 1 and 8));create unique index if not exists commercial_ai_playbooks_one_active on public.commercial_ai_playbooks(organization_id,scope_type,coalesce(developer_name,''),stage_key)where status='active';alter table public.commercial_ai_playbooks enable row level security;create policy commercial_ai_playbooks_scope on public.commercial_ai_playbooks for select to authenticated using(organization_id=(select public.current_organization_id()));revoke all on public.commercial_ai_playbooks from anon;grant select on public.commercial_ai_playbooks to authenticated;grant all on public.commercial_ai_playbooks to service_role;
create or replace function public.publish_commercial_ai_playbook(p_actor_id uuid,p_organization_id uuid,p_scope_type text,p_developer_name text,p_stage_key text,p_objective text,p_questions text[],p_actions text[],p_exit_criteria text[],p_prohibited_actions text[])returns uuid language plpgsql security definer set search_path=''as $$declare v_role text;v_version int;v_id uuid;begin select coalesce(commercial_role,case role when'admin'then'director'else role end)into v_role from public.profiles where id=p_actor_id and organization_id=p_organization_id and active=true;if v_role<>'director'then raise exception'playbook_director_only';end if;if p_scope_type not in('organization','developer')or p_stage_key not in('abordagem','qualificacao','apresentacao','simulacao','visita','proposta','fechamento','reativacao')or char_length(trim(p_objective))not between 10 and 500 or cardinality(p_questions)not between 1 and 8 or cardinality(p_actions)not between 1 and 8 or cardinality(p_exit_criteria)not between 1 and 8 or cardinality(p_prohibited_actions)not between 1 and 8 then raise exception'playbook_invalid';end if;perform pg_advisory_xact_lock(hashtextextended(p_organization_id::text||p_scope_type||coalesce(p_developer_name,'')||p_stage_key,0));select coalesce(max(version),0)+1 into v_version from public.commercial_ai_playbooks where organization_id=p_organization_id and scope_type=p_scope_type and developer_name is not distinct from case when p_scope_type='developer'then trim(p_developer_name)else null end and stage_key=p_stage_key;update public.commercial_ai_playbooks set status='retired'where organization_id=p_organization_id and scope_type=p_scope_type and developer_name is not distinct from case when p_scope_type='developer'then trim(p_developer_name)else null end and stage_key=p_stage_key and status='active';insert into public.commercial_ai_playbooks(organization_id,scope_type,developer_name,stage_key,version,status,objective,questions,actions,exit_criteria,prohibited_actions,created_by,approved_by,approved_at)values(p_organization_id,p_scope_type,case when p_scope_type='developer'then trim(p_developer_name)else null end,p_stage_key,v_version,'active',trim(p_objective),p_questions,p_actions,p_exit_criteria,p_prohibited_actions,p_actor_id,p_actor_id,now())returning id into v_id;return v_id;end$$;revoke all on function public.publish_commercial_ai_playbook(uuid,uuid,text,text,text,text,text[],text[],text[],text[])from public,anon,authenticated;grant execute on function public.publish_commercial_ai_playbook(uuid,uuid,text,text,text,text,text[],text[],text[],text[])to service_role;commit;
